    case IN_PROGRESS: System.out.println("Processing..."); break;
    case SUCCESS:     System.out.println("Payment successful!"); break;
    case FAILED:      System.out.println("Payment failed."); break;
    case UNKNOWN:     System.out.println("Transaction not found."); break;
}

